import uuid
import pytest

def test_open_savings_account_decision_table_unverified_customer(api_client, unverified_customer):
    payload = {
        "customer_id": unverified_customer["id"],
        "initial_deposit": 500.00
    }
    headers = {"Idempotency-Key": str(uuid.uuid4())}

    response = api_client.post("/accounts/savings", json=payload, headers=headers)

    assert response.status_code in (403, 422)
    body = response.json()
    error_text = str(body.get("error", body.get("detail", ""))).lower()
    assert "verif" in error_text or "forbidden" in error_text or "eligible" in error_text
